from .board import Board

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'black'
        self.game_over = False

    def switch_player(self):
        if self.current_player == 'black':
            self.current_player = 'white'
        else:
            self.current_player = 'black'

    def make_move(self, from_pos, to_pos):
        # Validate move
        piece = self.board.get_piece(from_pos)
        if piece and piece.color != self.current_player:
            raise ValueError("Not your turn")

        capture_positions = self.board.get_capture_moves(from_pos)

        # Check if capturing is mandatory
        if capture_positions:
            if to_pos not in capture_positions:
                raise ValueError("Capture move required")
        else:
            if self.board.is_valid_move(from_pos, to_pos):
                pass
            else:
                raise ValueError("Invalid move")

        # Perform the move
        self.board.move_piece(from_pos, to_pos)
        piece = self.board.get_piece(to_pos)

        # Check for kinging
        if (self.current_player == 'black' and to_pos[0] == 7) or \
           (self.current_player == 'white' and to_pos[0] == 0):
            piece.promote_to_king()

        # Switch player
        self.switch_player()

    def is_game_over(self):
        return self.game_over

    def get_board_state(self):
        return self.board.get_state()
