from .piece import Piece

class Board:
    def __init__(self):
        self.state = [['' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ['black', 'white']
        positions = [(i, j) for i in range(3) for j in range(0, 8, 2)] + [(i, j) for i in range(5, 8) for j in range(1, 9, 2)]
        for color, pos in zip(colors * 4, positions):
            self.state[pos[0]][pos[1]] = Piece(color)

    def get_state(self):
        return '\n'.join([' '.join(row) for row in self.state])

    def get_piece(self, position):
        x, y = position
        return self.state[x][y]

    def move_piece(self, from_pos, to_pos):
        piece = self.get_piece(from_pos)
        if not piece:
            raise ValueError("No piece at the given position")

        self.state[from_pos[0]][from_pos[1]] = ''
        self.state[to_pos[0]][to_pos[1]] = piece

    def get_capture_moves(self, from_pos):
        x, y = from_pos
        capture_positions = []
        piece = self.get_piece(from_pos)

        if piece.color == 'black':
            moves = [(-1, -1), (-1, 1)]
        else:
            moves = [(1, -1), (1, 1)]

        for dx, dy in moves:
            next_pos = (x + dx, y + dy)
            capture_pos = (next_pos[0] + dx, next_pos[1] + dy)

            if 0 <= next_pos[0] < 8 and 0 <= next_pos[1] < 8 and 0 <= capture_pos[0] < 8 and 0 <= capture_pos[1] < 8:
                piece_at_next = self.get_piece(next_pos)
                piece_at_capture = self.get_piece(capture_pos)

                if piece_at_next and piece_at_next.color != piece.color and not piece_at_capture:
                    capture_positions.append(capture_pos)

        return capture_positions

    def is_valid_move(self, from_pos, to_pos):
        x, y = from_pos
        dx, dy = to_pos[0] - x, to_pos[1] - y
        piece = self.get_piece(from_pos)

        if not piece:
            return False

        if abs(dx) != 1 or abs(dy) > 2:
            return False

        if abs(dy) == 1 and dx * dy < 0:
            return False

        next_pos = (x + dx, y + dy)
        capture_pos = (next_pos[0] + dx, next_pos[1] + dy)

        piece_at_next = self.get_piece(next_pos)
        piece_at_capture = self.get_piece(capture_pos)

        if piece_at_next and piece_at_next.color == piece.color:
            return False

        if abs(dy) == 2 and not piece_at_capture:
            middle_piece = (x + dx // 2, y + dy // 2)
            middle_piece_state = self.get_piece(middle_piece)
            if not middle_piece_state or middle_piece_state.color != piece.color:
                return False
        else:
            if piece_at_next:
                return False

        return True
```

