```python
class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def king_piece(self):
        self.king = True

    def is_king(self):
        return self.king


class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ['B', 'W']
        for i in range(3):
            for j in range(0, 8, 2):
                if (i + j) % 2 == 1:
                    self.board[i][j] = Piece(colors[(i + j) // 2])
        for i in range(5, 8):
            for j in range(0, 8, 2):
                if (i + j) % 2 == 1:
                    self.board[i][j] = Piece(colors[1 - (i + j) // 2])

    def print_board(self):
        for row in self.board:
            print(' '.join(piece.color + 'K' if piece else '.' for piece in row))

    def move_piece(self, start_pos, end_pos):
        piece = self.board[start_pos[0]][start_pos[1]]
        if piece is not None:
            self.board[end_pos[0]][end_pos[1]] = piece
            self.board[start_pos[0]][start_pos[1]] = None
            if (end_pos[0] == 0 and piece.color == 'W') or (end_pos[0] == 7 and piece.color == 'B'):
                piece.king_piece()


class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'W'

    def print_board(self):
        self.board.print_board()

    def switch_turn(self):
        self.current_player = 'B' if self.current_player == 'W' else 'W'

    def get_move(self):
        move_input = input(f"Player {self.current_player}, enter your move (from-to): ")
        start_pos, end_pos = map(int, move_input.split('-'))
        return [(start_pos // 8, start_pos % 8), (end_pos // 8, end_pos % 8)]

    def is_valid_move(self, start_pos, end_pos):
        piece = self.board.board[start_pos[0]][start_pos[1]]
        if piece is None or piece.color != self.current_player:
            return False
        # Simple move validation (no capturing logic yet)
        if abs(start_pos[0] - end_pos[0]) == 1 and abs(start_pos[1] - end_pos[1]) == 1:
            if self.board.board[end_pos[0]][end_pos[1]] is None:
                return True
        # TODO: Add capturing logic here
        return False

    def make_move(self):
        start_pos, end_pos = self.get_move()
        while not self.is_valid_move(start_pos, end_pos):
            print("Invalid move. Please try again.")
            start_pos, end_pos = self.get_move()
        self.board.move_piece(start_pos, end_pos)
        self.switch_turn()


def main():
    game = Game()
    while True:
        game.print_board()
        game.make_move()

if __name__ == "__main__":
    main()
```

